enum thread_type {
        /*
         * Kernel-level threads
         * 1. Without FPU states
         * 2. Won't swap TLS
         */
        TYPE_IDLE = 0, /* IDLE thread dose not have stack, pause cpu */
        TYPE_KERNEL = 1, /* KERNEL thread has stack */

