         * User-level threads
         * Should be larger than TYPE_KERNEL!
         */
        TYPE_USER = 2,
        TYPE_SHADOW = 3, /* SHADOW thread is used to achieve migrate IPC */
        TYPE_REGISTER = 4, /* Use as the IPC register callback threads */
        TYPE_TRACEE = 5, /* Traced thread for gdb server */
