static inline int sched_dequeue(struct thread *thread)
{
        return cur_sched_ops->sched_dequeue(thread);
}

/* Syscalls */
void sys_yield(void);
void sys_top(void);
int sys_suspend(unsigned long thread_cap);
int sys_resume(unsigned long thread_cap);

#endif /* SCHED_SCHED_H */

